(function () {
  'use strict';

  // ---- Constants (generated by encrypt.mjs --init) ----
  var SALT_HEX = '15f1ae5a6c02386a8e75a1643b0e5248';
  var VERIFIER = 'e8818adc2fd6767b32b4b27bdf623a45f304d5d88f441e6f8cd4884cb362ec1a';
  var PBKDF2_ITERATIONS = 100000;

  var hasNativeCrypto = !!(window.crypto && window.crypto.subtle);
  var forgeReady = window.__forgeReady || Promise.resolve();

  // ---- Helpers ----

  function hexToBytes(hex) {
    var bytes = new Uint8Array(hex.length / 2);
    for (var i = 0; i < bytes.length; i++) {
      bytes[i] = parseInt(hex.substr(i * 2, 2), 16);
    }
    return bytes;
  }

  function bytesToHex(bytes) {
    return Array.from(bytes).map(function (b) { return b.toString(16).padStart(2, '0'); }).join('');
  }

  function b64ToBytes(b64) {
    var bin = atob(b64);
    var bytes = new Uint8Array(bin.length);
    for (var i = 0; i < bin.length; i++) bytes[i] = bin.charCodeAt(i);
    return bytes;
  }

  function bytesToBinaryStr(bytes) {
    var s = '';
    for (var i = 0; i < bytes.length; i++) s += String.fromCharCode(bytes[i]);
    return s;
  }

  // ---- Core crypto ----

  async function deriveRawKey(password) {
    await forgeReady;
    if (hasNativeCrypto) {
      var enc = new TextEncoder();
      var keyMaterial = await crypto.subtle.importKey(
        'raw', enc.encode(password), 'PBKDF2', false, ['deriveBits']
      );
      var bits = await crypto.subtle.deriveBits(
        { name: 'PBKDF2', salt: hexToBytes(SALT_HEX), iterations: PBKDF2_ITERATIONS, hash: 'SHA-256' },
        keyMaterial, 256
      );
      return new Uint8Array(bits);
    }
    var salt = bytesToBinaryStr(hexToBytes(SALT_HEX));
    var derived = forge.pkcs5.pbkdf2(password, salt, PBKDF2_ITERATIONS, 32, forge.md.sha256.create());
    return new Uint8Array(derived.split('').map(function (c) { return c.charCodeAt(0); }));
  }

  async function sha256Hex(data) {
    await forgeReady;
    if (hasNativeCrypto) {
      var hash = await crypto.subtle.digest('SHA-256', data);
      return bytesToHex(new Uint8Array(hash));
    }
    var md = forge.md.sha256.create();
    md.update(bytesToBinaryStr(new Uint8Array(data)));
    return md.digest().toHex();
  }

  // ---- Public API ----

  async function verify(password) {
    var rawKey = await deriveRawKey(password);
    var hash = await sha256Hex(rawKey);
    return hash === VERIFIER;
  }

  async function deriveKeyHex(password) {
    var rawKey = await deriveRawKey(password);
    return bytesToHex(rawKey);
  }

  async function decryptWithKey(hexKey, encryptedB64, ivB64) {
    await forgeReady;
    if (hasNativeCrypto) {
      var rawKey = hexToBytes(hexKey);
      var aesKey = await crypto.subtle.importKey('raw', rawKey, { name: 'AES-GCM' }, false, ['decrypt']);
      var plainBuf = await crypto.subtle.decrypt(
        { name: 'AES-GCM', iv: b64ToBytes(ivB64) },
        aesKey, b64ToBytes(encryptedB64)
      );
      return new TextDecoder().decode(plainBuf);
    }
    var encryptedBytes = b64ToBytes(encryptedB64);
    var ciphertext = forge.util.createBuffer(bytesToBinaryStr(encryptedBytes.slice(0, -16)));
    var tag = forge.util.createBuffer(bytesToBinaryStr(encryptedBytes.slice(-16)));
    var key = forge.util.hexToBytes(hexKey);
    var iv = forge.util.decode64(ivB64);
    var decipher = forge.cipher.createDecipher('AES-GCM', key);
    decipher.start({ iv: iv, tag: tag });
    decipher.update(ciphertext);
    if (!decipher.finish()) throw new Error('Decryption failed');
    return decipher.output.toString();
  }

  async function decrypt(password, encryptedB64, ivB64) {
    var rawKey = await deriveRawKey(password);
    var hexKey = bytesToHex(rawKey);
    return decryptWithKey(hexKey, encryptedB64, ivB64);
  }

  // ---- Expose ----

  window.LettersAuth = {
    verify: verify,
    deriveKeyHex: deriveKeyHex,
    decrypt: decrypt,
    decryptWithKey: decryptWithKey,
    SALT_HEX: SALT_HEX,
    VERIFIER: VERIFIER
  };
})();
